//! Acceptance test for AC2 (MUST) — generated by `autobuilder scaffold`.
//!
//! Project: mqo-eval (cli)
//! AC description: Per-question verdict is correct/wrong/no_bind as appropriate based on agent output vs expected_answer
//! Test predicate: cargo test -- ac2_verdict_values
//!
//! Ownership split: this //! header block (AC metadata) is
//! read-only — to change an AC, file
//! agent/intent_card_amendment_request.json and re-scaffold. The
//! `fn acceptance_ac2` body BELOW is owned by the edit-agent: replace
//! the panic stub with a real assertion that verifies the AC
//! description above.

#![allow(
    clippy::unwrap_used,
    clippy::expect_used,
    clippy::doc_markdown,
    clippy::uninlined_format_args,
    clippy::indexing_slicing,
)]

use mqo_eval::{
    run::{run, OutputFormat, RunConfig},
    types::{OracleMode, Verdict},
};

fn write_stub_returning(dir: &tempfile::TempDir, answer: &str) -> String {
    use std::os::unix::fs::PermissionsExt;
    let path = dir.path().join(format!("stub_{answer}.sh"));
    let script = format!(
        "#!/bin/sh\necho '{{\"bound_mqo\":\"stub\",\"result_rows\":[[\"{answer}\"]],\"confidence\":0.8,\"pillars_fired\":[\"bind\"]}}'\n",
        answer = answer
    );
    std::fs::write(&path, script).expect("write stub");
    let mut perms = std::fs::metadata(&path).expect("metadata").permissions();
    perms.set_mode(0o755);
    std::fs::set_permissions(&path, perms).expect("set permissions");
    path.to_string_lossy().into_owned()
}

fn write_no_bind_stub(dir: &tempfile::TempDir) -> String {
    use std::os::unix::fs::PermissionsExt;
    let path = dir.path().join("stub_nobind.sh");
    // Empty output → no answer → no_bind verdict.
    std::fs::write(&path, "#!/bin/sh\necho ''\n").expect("write no-bind stub");
    let mut perms = std::fs::metadata(&path).expect("metadata").permissions();
    perms.set_mode(0o755);
    std::fs::set_permissions(&path, perms).expect("set permissions");
    path.to_string_lossy().into_owned()
}

fn write_single_question(tmp: &tempfile::TempDir, id: &str, expected: &str) -> String {
    let path = tmp.path().join(format!("q_{id}.yaml"));
    let yaml = format!(
        "questions:\n  - id: {id}\n    text: 'test question'\n    expected_answer: '{expected}'\n    model: tb/m\n"
    );
    std::fs::write(&path, yaml).expect("write yaml");
    path.to_string_lossy().into_owned()
}

#[test]
fn acceptance_ac2() {
    let tmp = tempfile::tempdir().unwrap();

    // --- correct ---
    {
        let agent_cmd = write_stub_returning(&tmp, "42");
        let q_path = write_single_question(&tmp, "q1", "42");
        let out = tmp.path().join("r_correct.json");
        let cfg = RunConfig {
            questions_path: q_path,
            model: "tb/m".to_owned(),
            agent_cmd,
            oracle: OracleMode::Fixture,
            pg_host: None,
            pg_pass_env: "ATSCALE_PG_PASS".to_owned(),
            out_path: out.to_string_lossy().into_owned(),
            format: OutputFormat::Text,
            results_dir: tmp.path().join("results").to_string_lossy().into_owned(),
            catalog: None,
            max_result_rows: 1000,
        };
        let results = run(&cfg).unwrap();
        assert_eq!(results[0].verdict, Verdict::Correct, "exact-match answer should be correct");
    }

    // --- wrong ---
    {
        let agent_cmd = write_stub_returning(&tmp, "99");
        let q_path = write_single_question(&tmp, "q2", "42");
        let out = tmp.path().join("r_wrong.json");
        let cfg = RunConfig {
            questions_path: q_path,
            model: "tb/m".to_owned(),
            agent_cmd,
            oracle: OracleMode::Fixture,
            pg_host: None,
            pg_pass_env: "ATSCALE_PG_PASS".to_owned(),
            out_path: out.to_string_lossy().into_owned(),
            format: OutputFormat::Text,
            results_dir: tmp.path().join("results").to_string_lossy().into_owned(),
            catalog: None,
            max_result_rows: 1000,
        };
        let results = run(&cfg).unwrap();
        assert_eq!(results[0].verdict, Verdict::Wrong, "mismatched answer should be wrong");
    }

    // --- no_bind ---
    {
        let agent_cmd = write_no_bind_stub(&tmp);
        let q_path = write_single_question(&tmp, "q3", "42");
        let out = tmp.path().join("r_nobind.json");
        let cfg = RunConfig {
            questions_path: q_path,
            model: "tb/m".to_owned(),
            agent_cmd,
            oracle: OracleMode::Fixture,
            pg_host: None,
            pg_pass_env: "ATSCALE_PG_PASS".to_owned(),
            out_path: out.to_string_lossy().into_owned(),
            format: OutputFormat::Text,
            results_dir: tmp.path().join("results").to_string_lossy().into_owned(),
            catalog: None,
            max_result_rows: 1000,
        };
        let results = run(&cfg).unwrap();
        assert_eq!(results[0].verdict, Verdict::NoBind, "empty agent output should be no_bind");
    }
}
